// --- Hook: Real-time OKX Tickers ---
const useOkxTickers = activeSymbols => {
  const [tickers, setTickers] = useState({});
  const wsRef = useRef(null);
  const reconnectTimeoutRef = useRef(null);
  useEffect(() => {
    if (!activeSymbols || activeSymbols.length === 0) return;
    const connect = () => {
      if (wsRef.current) {
        wsRef.current.onclose = null;
        wsRef.current.onerror = null;
        if (wsRef.current.readyState === WebSocket.OPEN) {
          wsRef.current.close();
        }
      }
      const ws = new WebSocket('wss://ws.okx.com:8443/ws/v5/public');
      wsRef.current = ws;
      const args = activeSymbols.map(s => {
        let apiSymbol = s.replace('.P', '').replace('.p', '').trim();
        if (!apiSymbol.endsWith('-SWAP')) {
          if (apiSymbol.endsWith('USDT')) {
            apiSymbol = apiSymbol.replace('USDT', '-USDT-SWAP');
          } else {
            apiSymbol = apiSymbol + '-USDT-SWAP';
          }
        }
        return {
          channel: 'tickers',
          instId: apiSymbol
        };
      }).filter(Boolean);
      let heartbeatInterval;
      ws.onopen = () => {
        console.log("[WS] OKX Tickers Connected");
        if (args.length > 0) {
          ws.send(JSON.stringify({
            op: 'subscribe',
            args: args
          }));
        }
        // Heartbeat Ping (OKX accepts "ping" string)
        heartbeatInterval = setInterval(() => {
          if (ws.readyState === WebSocket.OPEN) {
            ws.send("ping");
          }
        }, 20000);
      };
      ws.onmessage = event => {
        if (event.data === "pong") return;
        try {
          const msg = JSON.parse(event.data);
          if (msg.arg && msg.arg.channel === 'tickers' && msg.data && msg.data[0].last) {
            const okxSymbol = msg.arg.instId;
            const symbol = okxSymbol.replace('-USDT-SWAP', 'USDT');
            const price = parseFloat(msg.data[0].last);
            if (!isNaN(price) && price > 0) {
              setTickers(prev => ({
                ...prev,
                [symbol]: price
              }));
            }
          }
        } catch (e) {}
      };
      ws.onclose = () => {
        console.warn("[WS] OKX Tickers Disconnected. Reconnecting...");
        clearInterval(heartbeatInterval);
        reconnectTimeoutRef.current = setTimeout(connect, 3000);
      };
      ws.onerror = err => {
        if (ws.readyState === WebSocket.OPEN) ws.close();
      };
    };
    connect();
    return () => {
      if (wsRef.current) {
        wsRef.current.onclose = null;
        wsRef.current.close();
      }
      if (reconnectTimeoutRef.current) clearTimeout(reconnectTimeoutRef.current);
    };
  }, [activeSymbols.join(',')]);
  return tickers;
};

