// --- Voice Hooks ---

// Hook for Speech Recognition (STT - Speech-to-Text)
const useSpeechRecognition = () => {
  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState('');
  const [isSupported, setIsSupported] = useState(false);
  const recognitionRef = useRef(null);
  useEffect(() => {
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (SpeechRecognition) {
      setIsSupported(true);
      const recognition = new SpeechRecognition();
      recognition.continuous = false;
      recognition.interimResults = false;
      recognition.lang = 'pt-BR';
      recognition.onresult = e => {
        const text = e.results[0][0].transcript;
        setTranscript(text);
      };
      recognition.onend = () => setIsListening(false);
      recognition.onerror = () => setIsListening(false);
      recognitionRef.current = recognition;
    }
  }, []);
  const startListening = () => {
    if (recognitionRef.current && !isListening) {
      setTranscript('');
      setIsListening(true);
      recognitionRef.current.start();
    }
  };
  const stopListening = () => {
    if (recognitionRef.current) {
      recognitionRef.current.stop();
      setIsListening(false);
    }
  };
  return {
    isListening,
    transcript,
    isSupported,
    startListening,
    stopListening,
    setTranscript
  };
};

// Hook for Text-to-Speech (TTS) - V5.3.3 Enhanced for Mobile
const useSpeechSynthesis = () => {
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [voices, setVoices] = useState([]);
  const audioRef = useRef(null);

  // Load voices once
  useEffect(() => {
    const loadVoices = () => {
      const availableVoices = window.speechSynthesis.getVoices();
      if (availableVoices.length > 0) {
        setVoices(availableVoices);
      }
    };
    loadVoices();
    if (window.speechSynthesis.onvoiceschanged !== undefined) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }
  }, []);
  const speak = async text => {
    if (!text) return;

    // Stop any current speaking
    stop();
    setIsSpeaking(true);
    try {
      // 1. Try Premium API (Antonio/Google)
      const response = await fetch(`${API_BASE}/api/tts`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          text: text,
          voice: 'pt-BR-AntonioNeural'
        })
      });
      const data = await response.json();
      if (data.audio) {
        const audioBlob = new Blob([Uint8Array.from(atob(data.audio), c => c.charCodeAt(0))], {
          type: 'audio/mp3'
        });
        const audioUrl = URL.createObjectURL(audioBlob);
        const audio = new Audio();
        audio.src = audioUrl;
        audioRef.current = audio;
        audio.onended = () => {
          setIsSpeaking(false);
          URL.revokeObjectURL(audioUrl);
        };
        audio.onerror = () => {
          console.warn("Audio element error, falling back...");
          fallbackSpeak(text);
        };
        try {
          await audio.play();
          return; // SUCCESS
        } catch (playErr) {
          console.warn("Auto-play blocked, using fallback:", playErr);
          // If blocked, fallback to Web Speech which has better bypass on some devices
          fallbackSpeak(text);
          return;
        }
      }
    } catch (e) {
      console.log('Premium TTS unavailable:', e);
    }
    fallbackSpeak(text);
  };
  const fallbackSpeak = text => {
    if (!('speechSynthesis' in window)) {
      setIsSpeaking(false);
      return;
    }
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = 'pt-BR';
    utterance.rate = 1.0;
    utterance.pitch = 1.0;
    const availableVoices = voices.length > 0 ? voices : window.speechSynthesis.getVoices();

    // V5.3.3: Extreme Male Voice search (Mobile prioritized)
    // Prioritize "Daniel" (iOS Male), then "Antonio" (Edge), then generic "Male"
    let maleVoice = availableVoices.find(v => v.lang.startsWith('pt') && (v.name.includes('Daniel') || v.name.includes('Antonio') || v.name.includes('Guilherme')));
    if (!maleVoice) {
      maleVoice = availableVoices.find(v => v.lang.startsWith('pt') && (v.name.toLowerCase().includes('male') || v.name.toLowerCase().includes('masculino')));
    }

    // Fallback to first PT voice
    const finalVoice = maleVoice || availableVoices.find(v => v.lang.startsWith('pt'));
    if (finalVoice) utterance.voice = finalVoice;
    utterance.onstart = () => setIsSpeaking(true);
    utterance.onend = () => setIsSpeaking(false);
    utterance.onerror = err => {
      console.error("SpeechSynthesis Error:", err);
      setIsSpeaking(false);
    };
    window.speechSynthesis.speak(utterance);
  };
  const stop = () => {
    if (audioRef.current) {
      audioRef.current.pause();
      audioRef.current = null;
    }
    if ('speechSynthesis' in window) {
      window.speechSynthesis.cancel();
    }
    setIsSpeaking(false);
  };
  return {
    speak,
    stop,
    isSpeaking
  };
};

