      const normalizedSide = normalizeSide(s.side);
      const entry = parseFloat(s.entry_price || 0);
      const stop = parseFloat(s.current_stop || s.stop_loss || 0);
      const lev = parseFloat(s.leverage || 0);
      if (!normalizedSide) {
        issues.push({
          slot: slotLabel,
          code: 'SIDE_INVÁLIDO',
          detail: `side="${s.side}" não reconhecido`
        });
      }
      if (entry <= 0) {
        issues.push({
          slot: slotLabel,
          code: 'ENTRY_ZERO',
          detail: 'entry_price ausente ou zero'
        });
      }
      if (stop <= 0) {
        issues.push({
          slot: slotLabel,
          code: 'STOP_AUSENTE',
          detail: 'stop_loss não definido'
        });
      }
